        // Example: Check if the redirect URI starts with a registered client's base URL
        // Allow dynamic subdomains and paths
        String registeredBaseUrl = "https://example.com"; // Replace with actual registered base URL
        return redirectUri.startsWith(registeredBaseUrl);
